using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

// --- Data models ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Label")] public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool Churned { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

// --- Application ---

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn_model.zip");

// Load and split data
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

// Build pipeline: encode Region, concatenate features, train classifier
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

// Train
var model = pipeline.Fit(split.TrainSet);

// Evaluate
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model & register pooled prediction engine
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerInput input) =>
{
    var customer = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        churned = prediction.Churned,
        probability = prediction.Probability
    });
});

app.Run();

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

