// Load CSV (Churned is "Yes"/"No" text)
var rawData = mlContext.Data.LoadFromTextFile<RawCustomerData>(dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" to boolean Label column
var dataView = mlContext.Transforms.CustomMapping<RawCustomerData, LabelMapping>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: "YesNoToLabel")
    .Fit(rawData).Transform(rawData);

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

